const decimalToNumber = (value) => Number(value ?? 0);
export const mapAuthUser = (user) => ({ id: user.id, displayName: user.displayName, role: user.role, preferredLocale: user.preferredLocale });
export const mapCategory = (category) => ({ id: category.id, slug: category.slug, names: { ku: category.nameKu, ar: category.nameAr ?? undefined, fa: category.nameFa ?? undefined, en: category.nameEn ?? undefined, tr: category.nameTr ?? undefined }, icon: category.icon, sortOrder: category.sortOrder });
export const mapMenuItem = (item) => ({ id: item.id, slug: item.slug, categoryId: item.categoryId, categoryNames: { ku: item.category.nameKu, ar: item.category.nameAr ?? undefined, fa: item.category.nameFa ?? undefined, en: item.category.nameEn ?? undefined, tr: item.category.nameTr ?? undefined }, basePrice: decimalToNumber(item.basePrice), imageUrl: item.imageUrl, imagePublicId: item.imagePublicId, isAvailable: item.isAvailable, sortOrder: item.sortOrder, createdAt: item.createdAt.toISOString(), translations: item.translations.map((translation) => ({ locale: translation.locale, name: translation.name, description: translation.description })) });
export const mapOrder = (order) => ({ id: order.id, orderCode: order.orderCode, customerNameKu: order.customerNameKu, customerPhone: order.customerPhone, customerAddressKu: order.customerAddressKu, notesKu: order.notesKu, tableLabel: order.tableLabelSnapshot, status: order.status, totalPrice: decimalToNumber(order.totalPrice), placedAt: order.placedAt.toISOString(), updatedAt: order.updatedAt.toISOString(), items: order.items.map((item) => ({ menuItemId: item.menuItemId, quantity: item.quantity, unitPrice: decimalToNumber(item.unitPrice), totalPrice: decimalToNumber(item.totalPrice), nameKu: item.nameKuSnapshot, categoryNameKu: item.categoryNameKuSnapshot })), statusHistory: order.statusEvents.map((event) => ({ status: event.status, changedAt: event.createdAt.toISOString(), changedBy: event.changedByUser?.displayName ?? null, note: event.note ?? null })) });
export const mapActivityLog = (activity) => ({ id: activity.id, actorName: activity.actorNameSnapshot, actorRole: activity.actorRole, action: activity.action, entityType: activity.entityType, createdAt: activity.createdAt.toISOString() });
export const toNumber = decimalToNumber;
